          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "title": "分离器固定压力模式缺少操作压力目标",
          "citations": [
            "diag-3",
            "flowdoc-unit-2",
            "snapshot-1"
          ]
        },
        {
          "title": "分离器液相出口当前未连接且下游状态依赖尚未消除",
          "citations": [
            "diag-1",
            "diag-5",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        },
        {
          "title": "泵效率参数超出推荐范围",
          "citations": [
            "diag-4",
            "flowdoc-unit-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Booster Pump 提议提高出口压力目标并保留效率修正占位",
          "target": {
            "type": "unit",
            "id": "pump-13"
          },
          "rationale": "当前泵入口流 pressure_kpa=200，而泵配置中的 outlet_pressure_target_kpa=150，直接触发出口压力目标无效诊断；同时 efficiency_percent=109 超出推荐范围。基于现有证据，最小可审查提案是把出口压力目标调整到高于入口压力的待确认值，并把效率修正限制为占位而非武断替换具体数值。",
          "patch": {
            "parameter_updates": {
              "outlet_pressure_target_kpa": {
                "mode": "replace",
                "value": 220
              }
            },
            "parameter_placeholders": {
              "efficiency_percent": {
                "purpose": "replace_with_in_range_value",
                "constraints": {
                  "must_be_less_than_or_equal_to": 100
                }
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "diag-4",
            "flowdoc-unit-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Product Separator 补充固定压力目标占位",
          "target": {
            "type": "unit",
            "id": "separator-10"
          },
          "rationale": "分离器已处于 fixed pressure 模式，但 operating pressure target 缺失，存在直接错误诊断。现有文档仅能确认上游泵出口流和液相出口流的压力上下文，尚不足以唯一确定分离器目标压力，因此建议仅补充待确认的局部参数占位。",
          "patch": {
            "parameter_placeholders": {
              "operating_pressure_target_kpa": {
                "purpose": "required_for_fixed_pressure_mode",
                "suggested_range_hint": {
                  "lower_bound_kpa": 146,
                  "upper_bound_kpa": 158
                }
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
            "flowdoc-unit-2",
            "flowdoc-stream-2",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Separator Liquid 92 添加下游连接占位而不指定具体去向",
          "target": {
            "type": "stream",
            "id": "separator-liquid-92"
          },
          "rationale": "该液相流当前没有下游 consumer 或 export sink，造成拓扑无效；但诊断同时指出其路由仍依赖当前泵出口与分离器压力上下文。基于证据不足，不应臆造具体目标设备，仅应提出连接占位以待人工确认。",
          "patch": {
            "connection_placeholder": {
              "stream_id": "separator-liquid-92",
              "required_connection": "downstream_consumer_or_export_sink",
              "selection_constraint": {
                "do_not_infer_specific_target": true
              }
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "diag-5",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
